import React, { useState, useEffect } from 'react';
import { Platform, Alert } from 'react-native';
import { 
  purchaseItem,
  purchaseToken,
  getAvailablePurchases,
  finishTransaction,
  purchaseUpdatedListener,
  purchaseErrorListener
} from 'react-native-iap';
import { 
  GooglePay,
  ApplePay,
  Stripe,
  PayPal
} from 'react-native-payments';

const PaymentModule = () => {
  const [isInitialized, setIsInitialized] = useState(false);
  const [purchases, setPurchases] = useState([]);
  const [loading, setLoading] = useState(false);

  const initialize = async () => {
    try {
      if (Platform.OS === 'ios') {
        await GooglePay.isAvailable();
      }
      await ApplePay.isAvailable();
      await Stripe.setPublishableKey('pk_live_...');
      setIsInitialized(true);
    } catch (error) {
      console.error('Payment initialization failed:', error);
    }
  };

  const processPurchase = async (product, paymentMethod) => {
    setLoading(true);
    try {
      let transaction;
      
      if (paymentMethod === 'apple') {
        transaction = await purchaseItem(product.productId);
      } else if (paymentMethod === 'google') {
        transaction = await purchaseToken(product.productId);
      } else {
        transaction = await processExternalPayment(product, paymentMethod);
      }

      if (transaction) {
        await finishTransaction(transaction);
        await fetchPurchases();
        return { success: true, transaction };
      }
    } catch (error) {
      Alert.alert('Purchase Failed', error.message);
      return { success: false, error };
    } finally {
      setLoading(false);
    }
  };

  const processExternalPayment = async (product, method) => {
    try {
      switch (method) {
        case 'stripe':
          return await Stripe.createPaymentMethod({
            type: 'card',
            card: {
              number: product.cardNumber,
              exp_month: product.expMonth,
              exp_year: product.expYear,
              cvc: product.cvc
            }
          });
        case 'paypal':
          return await PayPal.createPayment({
            amount: product.amount,
            currency: product.currency
          });
        default:
          throw new Error('Unsupported payment method');
      }
    } catch (error) {
      throw new Error(`Payment processing failed: ${error.message}`);
    }
  };

  const fetchPurchases = async () => {
    try {
      const purchased = await getAvailablePurchases();
      setPurchases(purchased);
    } catch (error) {
      console.error('Failed to fetch purchases:', error);
    }
  };

  useEffect(() => {
    const purchaseUpdateSubscription = purchaseUpdatedListener(async (purchase) => {
      try {
        await finishTransaction(purchase);
        await fetchPurchases();
      } catch (error) {
        console.error('Error finishing purchase:', error);
      }
    });

    const purchaseErrorSubscription = purchaseErrorListener((error) => {
      console.error('Purchase error:', error);
    });

    initialize();

    return () => {
      purchaseUpdateSubscription.remove();
      purchaseErrorSubscription.remove();
    };
  }, []);

  return {
    isInitialized,
    purchases,
    loading,
    processPurchase,
    fetchPurchases
  };
};

export default PaymentModule;